pipeline.evaluate:
(async () => {
  const rawUrl = ${{ args.url | json }};
  const tweetId = String(rawUrl || '').match(/\/status\/(\d+)/)?.[1] || String(rawUrl || '').match(/^(\d+)$/)?.[1] || '';
  if (!tweetId) return [{ status: 'failed', message: 'Could not parse tweet ID from URL' }];

  const ct0 = document.cookie.split(';').map(c => c.trim()).find(c => c.startsWith('ct0='))?.split('=')[1];
  const bearer = 'AAAAAAAAAAAAAAAAAAAAANRILgAAAAAAnNwIzUejRCOuH5E6I8xnZz4puTs%3D1Zv7ttfk8LF81IUq16cHjhLTvJu4FA33AGWWjCpTnA';
  const headers = {
    Authorization: 'Bearer ' + decodeURIComponent(bearer),
    'X-Csrf-Token': ct0 || '',
    'X-Twitter-Auth-Type': 'OAuth2Session',
    'X-Twitter-Active-User': 'yes'
  };

  const apiAttempts = [];
  const apiTargets = [
    `https://api.x.com/2/tweets/${tweetId}`,
    `/i/api/2/tweets/${tweetId}`
  ];

  for (const apiUrl of apiTargets) {
    try {
      const resp = await fetch(apiUrl, {
        method: 'DELETE',
        credentials: 'include',
        headers
      });
      let text = '';
      try { text = await resp.text(); } catch {}
      apiAttempts.push(`${apiUrl} -> HTTP ${resp.status}${text ? ` ${text.slice(0, 120)}` : ''}`);
      if (resp.ok) {
        let data = null;
        try { data = JSON.parse(text); } catch {}
        if (!data || data.data?.deleted === true || data.deleted === true) {
          return [{ status: 'success', message: 'Tweet successfully deleted via API' }];
        }
      }
    } catch (e) {
      apiAttempts.push(`${apiUrl} -> ${String(e).slice(0, 120)}`);
    }
  }

  const detectCurrentUser = () => {
    const profileHref = document.querySelector('a[data-testid="AppTabBar_Profile_Link"]')?.getAttribute('href') || '';
    const fromProfile = profileHref.replace(/^\//, '').split('/')[0];
    if (/^[A-Za-z0-9_]{1,15}$/.test(fromProfile)) return fromProfile;
    const switcherText = document.querySelector('[data-testid="SideNav_AccountSwitcher_Button"]')?.textContent || '';
    const match = switcherText.match(/@([A-Za-z0-9_]{1,15})/);
    return match?.[1] || '';
  };
  const getPrimaryTweet = () => document.querySelector('[data-testid="primaryColumn"] article[data-testid="tweet"]') || document.querySelector('main article[data-testid="tweet"]') || document.querySelector('article[data-testid="tweet"]');
  const menuSelectors = [
    '[aria-label="More"]',
    '[aria-label="More menu items"]',
    '[data-testid="caret"]',
    'button[aria-haspopup="menu"]'
  ];
  const findMenuItem = (matcher) => {
    for (const item of document.querySelectorAll('[role="menuitem"]')) {
      const text = (item.textContent || '').trim();
      if (matcher(text)) return item;
    }
    return null;
  };
  const openDeleteFromTweet = async (tweetRoot) => {
    if (!tweetRoot) return { ok: false, reason: 'tweet root missing' };

    let menuButton = null;
    for (const selector of menuSelectors) {
      menuButton = tweetRoot.querySelector(selector);
      if (menuButton) break;
    }
    if (!menuButton) return { ok: false, reason: 'tweet menu missing' };

    menuButton.click();
    await new Promise(r => setTimeout(r, 1000));

    let deleteBtn = null;
    for (let attempts = 0; attempts < 10 && !deleteBtn; attempts += 1) {
      deleteBtn = findMenuItem(text => text.includes('Delete') && !text.includes('List'));
      if (!deleteBtn) await new Promise(r => setTimeout(r, 300));
    }
    if (!deleteBtn) return { ok: false, reason: 'delete item missing' };

    deleteBtn.click();
    await new Promise(r => setTimeout(r, 1000));

    const confirmBtn = document.querySelector('[data-testid="confirmationSheetConfirm"]');
    if (!confirmBtn) return { ok: false, reason: 'confirm dialog missing' };

    confirmBtn.click();
    await new Promise(r => setTimeout(r, 2000));
    return { ok: true };
  };

  let result = await openDeleteFromTweet(getPrimaryTweet());
  if (result.ok) return [{ status: 'success', message: 'Tweet successfully deleted' }];

  const username = detectCurrentUser();
  if (username) {
    try {
      location.href = 'https://x.com/' + username;
      await new Promise(r => setTimeout(r, 4000));
      const tweets = Array.from(document.querySelectorAll('[data-testid="tweet"]'));
      const targetTweet = tweets.find(tweet => (tweet.querySelector('a[href*="/status/"]')?.href || '').includes('/status/' + tweetId));
      const profileResult = await openDeleteFromTweet(targetTweet);
      if (profileResult.ok) {
        return [{ status: 'success', message: 'Tweet successfully deleted via profile timeline' }];
      }
      result = profileResult;
    } catch (e) {
      result = { ok: false, reason: String(e).slice(0, 120) };
    }
  }

  return [{ status: 'failed', message: 'Delete option not found (not your tweet); UI reason: ' + (result.reason || 'unknown') + '; API attempts: ' + apiAttempts.join(' | ') }];
})()
